function mergeLocalizedValue(base, localized) {
  if (localized === undefined) return base;
  if (Array.isArray(base) && Array.isArray(localized)) {
    return base.map((item, index) => mergeLocalizedValue(item, localized[index]));
  }
  if (base && localized && typeof base === "object" && typeof localized === "object") {
    return Object.fromEntries(
      Array.from(new Set([...Object.keys(base), ...Object.keys(localized)]))
        .map((key) => [key, mergeLocalizedValue(base[key], localized[key])])
    );
  }
  return localized;
}

export function localizeBlogPosts(posts, language) {
  if (!language?.startsWith("es")) return posts;
  return posts.map((post) => mergeLocalizedValue(post, spanishBlogContent[post.slug]));
}
